parameters.jsCode:
// قائمة أكواد الدول
const countryCodes = {
  'OM': '968', 'JO': '962', 'AE': '971', 'SA': '966', 'KW': '965',
  'QA': '974', 'BH': '973', 'EG': '20', 'IQ': '964', 'LB': '961',
  'SY': '963', 'PS': '970', 'YE': '967', 'US': '1', 'GB': '44',
  'DE': '49', 'FR': '33', 'IT': '39', 'ES': '34', 'TR': '90',
  'IN': '91', 'PK': '92'
};

// جلب البيانات من fulfilment trigger
const fulfillmentData = $('fulfilment').item.json;

const phone = fulfillmentData.destination?.phone ||
              fulfillmentData.shipping_address?.phone ||
              fulfillmentData.phone || 
              '';

const countryCode = fulfillmentData.destination?.country_code ||
                    fulfillmentData.shipping_address?.country_code ||
                    'OM';

// تنضيف الرقم
let formattedPhone = phone.trim().replace(/\s+/g, '').replace(/[^0-9+]/g, '');

// لو الرقم فاضي
if (!formattedPhone || formattedPhone.length < 5) {
  return {
    phone: phone,
    original_phone: phone,
    country_code: countryCode,
    validation_status: 'empty_or_invalid'
  };
}

// نشيك إذا الرقم بيبدأ بكود دولة
const startsWithCode = Object.values(countryCodes).some(code => {
  const cleanPhone = formattedPhone.replace('+', '');
  return cleanPhone.startsWith(code);
});

if (!startsWithCode) {
  // الرقم ما بيبدأ بكود - نضيف الكود حسب البلد
  const defaultCode = countryCodes[countryCode] || '968';
  const cleanPhone = formattedPhone.replace('+', '');
  formattedPhone = '+' + defaultCode + cleanPhone;
} else if (!formattedPhone.startsWith('+')) {
  // الكود موجود بس ما في علامة +
  formattedPhone = '+' + formattedPhone;
}

return {
  phone: formattedPhone,
  original_phone: phone,
  country_code: countryCode,
  validation_status: 'success'
};

